    /**
     * Extract the Issuer from an assertion element.
     */
    private String extractIssuer(Element assertionElement) throws SamlProcessingException {
        NodeList issuerNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing Issuer element");
        }

        String issuer = issuerNodes.item(0).getTextContent();
        if (issuer == null || issuer.trim().isEmpty()) {
            throw new SamlProcessingException("Assertion Issuer is empty");
        }

        return issuer.trim();
    }

    /**
     * Validate assertion Conditions including time bounds and audience restriction.
     */
    private void validateConditions(Element assertionElement) throws SamlProcessingException {
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(
            SAML2_ASSERTION_NS, "Conditions");

        if (conditionsNodes.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing Conditions element");
        }

        Element conditionsElement = (Element) conditionsNodes.item(0);

        // Validate NotBefore
        String notBefore = conditionsElement.getAttribute("NotBefore");
        if (notBefore != null && !notBefore.isEmpty()) {
            Instant notBeforeInstant = Instant.parse(notBefore);
            Instant now = Instant.now();
            if (now.plus(MAX_CLOCK_SKEW).isBefore(notBeforeInstant)) {
                throw new SamlProcessingException(
                    "Assertion is not yet valid (NotBefore condition not met)");
            }
        }

        // Validate NotOnOrAfter
        String notOnOrAfter = conditionsElement.getAttribute("NotOnOrAfter");
        if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
            Instant notOnOrAfterInstant = Instant.parse(notOnOrAfter);
            Instant now = Instant.now();
            if (now.minus(MAX_CLOCK_SKEW).isAfter(notOnOrAfterInstant) ||
                now.minus(MAX_CLOCK_SKEW).equals(notOnOrAfterInstant)) {
                throw new SamlProcessingException(
                    "Assertion has expired (NotOnOrAfter condition not met)");
            }
        }

        // Validate AudienceRestriction
        NodeList audienceRestrictionNodes = conditionsElement.getElementsByTagNameNS(
            SAML2_ASSERTION_NS, "AudienceRestriction");

        if (audienceRestrictionNodes.getLength() > 0) {
            Element audienceRestriction = (Element) audienceRestrictionNodes.item(0);
            NodeList audienceNodes = audienceRestriction.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "Audience");

            boolean audienceMatched = false;
            for (int i = 0; i < audienceNodes.getLength(); i++) {
                String audience = audienceNodes.item(i).getTextContent();
                if (expectedAudience.equals(audience != null ? audience.trim() : null)) {
                    audienceMatched = true;
                    break;
                }
            }

            if (!audienceMatched) {
                throw new SamlProcessingException(
                    "Assertion audience restriction does not include expected audience: " +
                    expectedAudience);
            }
        }
    }

    /**
     * Extract and validate the Subject element, returning the NameID.
     */
    private String extractAndValidateSubject(Element assertionElement) throws SamlProcessingException {
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing Subject element");
        }

        Element subjectElement = (Element) subjectNodes.item(0);

        // Extract NameID
        NodeList nameIdNodes = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() == 0) {
            throw new SamlProcessingException("Assertion Subject missing NameID element");
        }

        String nameId = nameIdNodes.item(0).getTextContent();
        if (nameId == null || nameId.trim().isEmpty()) {
            throw new SamlProcessingException("Assertion NameID is empty");
        }

        // Validate SubjectConfirmation
        NodeList subjectConfirmationNodes = subjectElement.getElementsByTagNameNS(
            SAML2_ASSERTION_NS, "SubjectConfirmation");

        if (subjectConfirmationNodes.getLength() > 0) {
            Element subjectConfirmation = (Element) subjectConfirmationNodes.item(0);
            String method = subjectConfirmation.getAttribute("Method");

            if (!"urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                throw new SamlProcessingException(
                    "Unsupported SubjectConfirmation method: " + sanitizeForLog(method));
            }

            // Validate SubjectConfirmationData
            NodeList scdNodes = subjectConfirmation.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "SubjectConfirmationData");

            if (scdNodes.getLength() > 0) {
                Element scd = (Element) scdNodes.item(0);

                // Check NotOnOrAfter
                String scdNotOnOrAfter = scd.getAttribute("NotOnOrAfter");
                if (scdNotOnOrAfter != null && !scdNotOnOrAfter.isEmpty()) {
                    Instant expiry = Instant.parse(scdNotOnOrAfter);
                    if (Instant.now().minus(MAX_CLOCK_SKEW).isAfter(expiry)) {
                        throw new SamlProcessingException(
                            "SubjectConfirmationData has expired");
                    }
                }

                // Validate Recipient matches our destination
                String recipient = scd.getAttribute("Recipient");
                if (recipient != null && !recipient.isEmpty()) {
                    if (!expectedDestination.equals(recipient)) {
                        throw new SamlProcessingException(
                            "SubjectConfirmationData Recipient does not match expected destination");
                    }
                }
            }
        }

        return nameId.trim();
    }

    /**
     * Validate the AuthnStatement element.
     */
    private void validateAuthnStatement(Element assertionElement) throws SamlProcessingException {
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(
            SAML2_ASSERTION_NS, "AuthnStatement");

        if (authnStatementNodes.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing AuthnStatement element");
        }

        Element authnStatement = (Element) authnStatementNodes.item(0);

        // Validate AuthnInstant
        String authnInstant = authnStatement.getAttribute("AuthnInstant");
        if (authnInstant != null && !authnInstant.isEmpty()) {
            validateTimestamp(authnInstant, "AuthnInstant");
        }

        // Check SessionNotOnOrAfter if present
        String sessionNotOnOrAfter = authnStatement.getAttribute("SessionNotOnOrAfter");
        if (sessionNotOnOrAfter != null && !sessionNotOnOrAfter.isEmpty()) {
            Instant sessionExpiry = Instant.parse(sessionNotOnOrAfter);
            if (Instant.now().minus(MAX_CLOCK_SKEW).isAfter(sessionExpiry)) {
                throw new SamlProcessingException("AuthnStatement session has expired");
            }
        }
    }

    /**
     * Extract user attributes from the AttributeStatement.
     */
    private Map<String, List<String>> extractAttributes(Element assertionElement) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();

        NodeList attrStatementNodes = assertionElement.getElementsByTagNameNS(
            SAML2_ASSERTION_NS, "AttributeStatement");

        if (attrStatementNodes.getLength() == 0) {
            return attributes;
        }

        Element attrStatement = (Element) attrStatementNodes.item(0);
        NodeList attrNodes = attrStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

        for (int i = 0; i < attrNodes.getLength(); i++) {
            Element attrElement = (Element) attrNodes.item(i);
            String attrName = attrElement.getAttribute("Name");

            if (attrName == null || attrName.isEmpty()) {
                continue;
            }

            // Validate attribute name against allowlist pattern
            if (!isValidAttributeName(attrName)) {
                LOGGER.warning("Skipping attribute with invalid name pattern");
                continue;
            }

            List<String> values = new ArrayList<>();
            NodeList valueNodes = attrElement.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "AttributeValue");

            for (int j = 0; j < valueNodes.getLength(); j++) {
                String value = valueNodes.item(j).getTextContent();
                if (value != null) {
                    // Limit attribute value length
                    if (value.length() > 4096) {
                        LOGGER.warning("Truncating oversized attribute value for: " + sanitizeForLog(attrName));
                        value = value.substring(0, 4096);
                    }
                    values.add(value.trim());
                }
            }

            attributes.put(attrName, Collections.unmodifiableList(values));
        }

        return Collections.unmodifiableMap(attributes);
    }

    /**
     * Validate a timestamp string is within acceptable bounds.
     */
    private void validateTimestamp(String timestampStr, String fieldName) throws SamlProcessingException {
        if (timestampStr == null || timestampStr.isEmpty()) {
            throw new SamlProcessingException(fieldName + " is missing or empty");
        }

        try {
            Instant timestamp = Instant.parse(timestampStr);
            Instant now = Instant.now();

            // Check if timestamp is too far in the future
            if (timestamp.isAfter(now.plus(MAX_CLOCK_SKEW))) {
                throw new SamlProcessingException(
                    fieldName + " is too far in the future (possible clock skew or attack)");
            }

            // Check if timestamp is too old (more than 1 hour + skew)
            if (timestamp.isBefore(now.minus(Duration.ofHours(1)).minus(MAX_CLOCK_SKEW))) {
                throw new SamlProcessingException(
                    fieldName + " is too old (possible replay attack)");
            }
        } catch (java.time.format.DateTimeParseException e) {
            throw new SamlProcessingException(fieldName + " has invalid format");
        }
    }

    /**
     * Validate attribute name against an allowlist pattern.
     */
    private boolean isValidAttributeName(String name) {
        // Allow standard SAML attribute name formats:
        // URIs, OIDs, and simple alphanumeric names
        return name.matches("^[a-zA-Z0-9._:/-]+$") && name.length() <= 512;
    }

    /**
     * Create an authenticated session from a validated SAML assertion.
     */
    private AuthenticatedSession createSession(SamlAssertion assertion) {
        String sessionId = generateSecureSessionId();
        Instant now = Instant.now();
        Instant expiry = now.plus(MAX_SESSION_DURATION);

        AuthenticatedSession session = new AuthenticatedSession(
            sessionId,
            assertion.getNameId(),
            assertion.getIssuer(),
            assertion.getAttributes(),
            now,
            expiry,
            assertion.getAssertionId()
        );

        activeSessions.put(sessionId, session);

        LOGGER.info("Created authenticated session. Expiry: " + expiry);

        return session;
    }

    /**
     * Generate a cryptographically secure session identifier.
     */
    private String generateSecureSessionId() {
        byte[] randomBytes = new byte[32];
        try {
            SecureRandom.getInstanceStrong().nextBytes(randomBytes);
        } catch (NoSuchAlgorithmException e) {
            new SecureRandom().nextBytes(randomBytes);
        }
        return Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
    }

    /**
     * Validate an existing session.
     */
    public AuthenticatedSession validateSession(String sessionId) {
        if (sessionId == null || sessionId.isEmpty()) {
            return null;
        }

        AuthenticatedSession session = activeSessions.get(sessionId);
        if (session == null) {
            return null;
        }

        if (session.isExpired()) {
            activeSessions.remove(sessionId);
            LOGGER.info("Session expired and removed");
            return null;
        }

        return session;
    }

    /**
     * Invalidate/logout a session.
     */
    public void invalidateSession(String sessionId) {
        if (sessionId != null) {
            AuthenticatedSession removed = activeSessions.remove(sessionId);
            if (removed != null) {
                LOGGER.info("Session invalidated");
            }
        }
    }

    /**
     * Clean up expired sessions.
     */
    public void cleanupExpiredSessions() {
        int removed = 0;
        Iterator<Map.Entry<String, AuthenticatedSession>> it = activeSessions.entrySet().iterator();
        while (it.hasNext()) {
            Map.Entry<String, AuthenticatedSession> entry = it.next();
            if (entry.getValue().isExpired()) {
                it.remove();
                removed++;
            }
        }
        if (removed > 0) {
            LOGGER.info("Cleaned up " + removed + " expired sessions");
        }
    }

    /**
     * Sanitize a string for safe logging (prevent log injection).
     */
    private static String sanitizeForLog(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n\\t]", "_")
                    .substring(0, Math.min(input.length(), 200));
    }

    // ==================== Inner Classes ====================

    /**
     * Represents a validated SAML assertion.
     */
    public static class SamlAssertion {
        private final String assertionId;
        private final String issuer;
        private final String nameId;
        private final Map<String, List<String>> attributes;
        private final Instant issueInstant;

        public SamlAssertion(String assertionId, String issuer, String nameId,
                             Map<String, List<String>> attributes, Instant issueInstant) {
            this.assertionId = assertionId;
            this.issuer = issuer;
            this.nameId = nameId;
            this.attributes = attributes;
            this.issueInstant = issueInstant;
        }

        public String getAssertionId() { return assertionId; }
        public String getIssuer() { return issuer; }
        public String getNameId() { return nameId; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public Instant getIssueInstant() { return issueInstant; }

        public String getFirstAttributeValue(String name) {
            List<String> values = attributes.get(name);
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "SamlAssertion{assertionId='" + assertionId +
                   "', issuer='" + issuer +
                   "', nameId='[REDACTED]'" +
                   ", attributeCount=" + attributes.size() + "}";
        }
    }

    /**
     * Represents an authenticated user session.
     */
    public static class AuthenticatedSession {
        private final String sessionId;
        private final String userId;
        private final String identityProvider;
        private final Map<String, List<String>> attributes;
        private final Instant createdAt;
        private final Instant expiresAt;
        private final String samlAssertionId;

        public AuthenticatedSession(String sessionId, String userId, String identityProvider,
                                     Map<String, List<String>> attributes,
                                     Instant createdAt, Instant expiresAt,
                                     String samlAssertionId) {
            this.sessionId = sessionId;
            this.userId = userId;
            this.identityProvider = identityProvider;
            this.attributes = attributes;
            this.createdAt = createdAt;
            this.expiresAt = expiresAt;
            this.samlAssertionId = samlAssertionId;
        }

        public String getSessionId() { return sessionId; }
        public String getUserId() { return userId; }
        public String getIdentityProvider() { return identityProvider; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public Instant getCreatedAt() { return createdAt; }
        public Instant getExpiresAt() { return expiresAt; }
        public String getSamlAssertionId() { return samlAssertionId; }

        public boolean isExpired() {
            return Instant.now().isAfter(expiresAt);
        }

        public String getFirstAttributeValue(String name) {
            List<String> values = attributes.get(name);
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "AuthenticatedSession{sessionId='[REDACTED]'" +
                   ", userId='[REDACTED]'" +
                   ", identityProvider='" + identityProvider +
                   "', createdAt=" + createdAt +
                   ", expiresAt=" + expiresAt +
                   ", attributeCount=" + attributes.size() + "}";
        }
    }

    /**
     * Custom exception for SAML processing errors.
     */
    public static class SamlProcessingException extends Exception {
        public SamlProcessingException(String message) {
            super(message);
        }

        public SamlProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }

